// // This module is designed to decrement a 4-bit binary counter on each rising edge of the clock signal, and reset to 15 on the rising edge of the reset signal.
module binary_counter (
  input clock,
  input reset,
  output reg [3:0] count
);

  always @(posedge clock) begin
    if (reset) begin
      count <= 4'b0000;
    end else begin
      count <= count + 1;
    end
  end

endmodule
